package dev.modichamiya.eclipse.gameplay.slayer;

import dev.modichamiya.eclipse.registry.ContentKey;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

public final class SlayerService {public enum State{FILLING,BOSS_READY,BOSS_ACTIVE,COMPLETED,FAILED}public static final class Quest{private final UUID owner;private final SlayerDefinition definition;private final SlayerDefinition.Tier tier;private long killXp;private State state=State.FILLING;private Quest(UUID owner,SlayerDefinition definition,SlayerDefinition.Tier tier){this.owner=owner;this.definition=definition;this.tier=tier;}public UUID owner(){return owner;}public State state(){return state;}public long killXp(){return killXp;}}
    private final Map<ContentKey,SlayerDefinition>definitions=new ConcurrentHashMap<>();private final Map<UUID,Quest>active=new ConcurrentHashMap<>();private final Map<UUID,Map<ContentKey,Long>>xp=new ConcurrentHashMap<>();public void register(SlayerDefinition definition){definitions.put(definition.key(),definition);}public Quest start(UUID player,ContentKey key,int tier){SlayerDefinition definition=Optional.ofNullable(definitions.get(key)).orElseThrow();Quest quest=new Quest(player,definition,Optional.ofNullable(definition.tiers().get(tier)).orElseThrow());if(active.putIfAbsent(player,quest)!=null)throw new IllegalStateException("Quest already active");return quest;}public synchronized State creditKill(UUID player,String family,long amount){Quest quest=Optional.ofNullable(active.get(player)).orElseThrow();if(quest.state!=State.FILLING||!quest.definition.mobFamily().equals(family))return quest.state;quest.killXp=Math.min(quest.tier.requiredKillXp(),Math.addExact(quest.killXp,amount));if(quest.killXp>=quest.tier.requiredKillXp())quest.state=State.BOSS_READY;return quest.state;}public synchronized void bossSpawned(UUID player){Quest q=active.get(player);if(q==null||q.state!=State.BOSS_READY)throw new IllegalStateException();q.state=State.BOSS_ACTIVE;}public synchronized long complete(UUID player){Quest q=active.remove(player);if(q==null||q.state!=State.BOSS_ACTIVE)throw new IllegalStateException();q.state=State.COMPLETED;return xp.computeIfAbsent(player,id->new ConcurrentHashMap<>()).merge(q.definition.key(),q.tier.rewardXp(),Math::addExact);}}
